#!/usr/bin/env python\n\"\"\"\nScript de backtesting complet\nSimule le trading historique et génère des rapports\n\"\"\"\n\nimport argparse\nfrom datetime import datetime, timedelta\nfrom typing import List, Dict\nimport json\nfrom src.utils.logger import get_logger\nfrom src.strategies import get_strategy\nfrom src.ai.indicators import TechnicalIndicators\nfrom src.core.risk_manager import RiskManager\n\nlogger = get_logger(\"backtest\")\n\n\nclass Backtester:\n    \"\"\"Moteur de backtesting\"\"\"\n    \n    def __init__(self, strategy_name: str = 'combined'):\n        \"\"\"Initialiser le backtester\"\"\"\n        self.strategy = get_strategy(strategy_name)\n        self.risk_manager = RiskManager()\n        self.trades = []\n        self.equity = 1000.0  # Équité initiale\n        logger.info(f\"🔄 Backtester initialisé avec stratégie: {strategy_name}\")\n    \n    def backtest(self, prices: List[float], timestamps: List[datetime] = None) -> Dict:\n        \"\"\"Exécuter un backtest complet\"\"\"\n        if not self.strategy:\n            logger.error(\"❌ Stratégie invalide\")\n            return {}\n        \n        initial_equity = self.equity\n        current_position = None\n        \n        for i, price in enumerate(prices):\n            # Analyser avec les prix jusqu'à présent\n            analysis = self.strategy.analyze(prices[:i+1])\n            signal = analysis.get('signal') or analysis.get('type')\n            \n            # BUY Signal\n            if signal == 'BUY' and not current_position:\n                if self.risk_manager.validate_order(price, 0.01):\n                    amount = 0.01\n                    cost = price * amount\n                    if cost <= self.equity:\n                        current_position = {\n                            'entry_price': price,\n                            'amount': amount,\n                            'entry_index': i,\n                            'entry_time': timestamps[i] if timestamps else None\n                        }\n                        self.equity -= cost\n                        logger.debug(f\"📈 BUY @ {price:.2f}\")\n            \n            # SELL Signal\n            elif signal == 'SELL' and current_position:\n                exit_price = price\n                proceeds = exit_price * current_position['amount']\n                pnl = proceeds - (current_position['entry_price'] * current_position['amount'])\n                pnl_percent = (pnl / (current_position['entry_price'] * current_position['amount'])) * 100\n                \n                self.equity += proceeds\n                self.risk_manager.record_trade_result(pnl_percent)\n                \n                self.trades.append({\n                    'entry_price': current_position['entry_price'],\n                    'exit_price': exit_price,\n                    'pnl': pnl,\n                    'pnl_percent': pnl_percent,\n                    'entry_index': current_position['entry_index'],\n                    'exit_index': i\n                })\n                \n                logger.debug(f\"📉 SELL @ {price:.2f} | PnL: {pnl_percent:.2f}%\")\n                current_position = None\n        \n        # Fermer toute position ouverte à la fin\n        if current_position:\n            final_price = prices[-1]\n            proceeds = final_price * current_position['amount']\n            self.equity += proceeds\n        \n        return self._generate_report(initial_equity)\n    \n    def _generate_report(self, initial_equity: float) -> Dict:\n        \"\"\"Générer un rapport de backtesting\"\"\"\n        total_return = self.equity - initial_equity\n        total_return_percent = (total_return / initial_equity) * 100\n        \n        winning_trades = [t for t in self.trades if t['pnl'] > 0]\n        losing_trades = [t for t in self.trades if t['pnl'] < 0]\n        \n        win_rate = (len(winning_trades) / len(self.trades)) * 100 if self.trades else 0\n        \n        avg_win = sum(t['pnl'] for t in winning_trades) / len(winning_trades) if winning_trades else 0\n        avg_loss = sum(t['pnl'] for t in losing_trades) / len(losing_trades) if losing_trades else 0\n        \n        profit_factor = abs(sum(t['pnl'] for t in winning_trades) / sum(t['pnl'] for t in losing_trades)) if losing_trades else 0\n        \n        report = {\n            'strategy': self.strategy.name,\n            'initial_equity': initial_equity,\n            'final_equity': self.equity,\n            'total_return': total_return,\n            'total_return_percent': total_return_percent,\n            'total_trades': len(self.trades),\n            'winning_trades': len(winning_trades),\n            'losing_trades': len(losing_trades),\n            'win_rate': win_rate,\n            'avg_win': avg_win,\n            'avg_loss': avg_loss,\n            'profit_factor': profit_factor\n        }\n        \n        return report\n\n\ndef main():\n    \"\"\"Fonction principale\"\"\"\n    parser = argparse.ArgumentParser(description=\"Backtester pour Hamx_smart\")\n    parser.add_argument(\"--strategy\", default=\"combined\", help=\"Stratégie à utiliser\")\n    parser.add_argument(\"--pair\", default=\"BTC/USDT\", help=\"Paire de trading\")\n    parser.add_argument(\"--output\", default=\"backtest_report.json\", help=\"Fichier de sortie\")\n    \n    args = parser.parse_args()\n    \n    # Générer des données de test\n    import random\n    logger.info(\"📊 Génération de données de test...\")\n    base_price = 100.0\n    prices = [base_price]\n    for _ in range(100):\n        change = random.uniform(-2, 2)\n        prices.append(prices[-1] * (1 + change/100))\n    \n    # Lancer le backtest\n    backtester = Backtester(strategy_name=args.strategy)\n    report = backtester.backtest(prices)\n    \n    # Sauvegarder le rapport\n    with open(args.output, 'w') as f:\n        json.dump(report, f, indent=2)\n    \n    # Afficher le rapport\n    logger.info(\"\\n\" + \"=\"*50)\n    logger.info(f\"📈 RAPPORT DE BACKTESTING\")\n    logger.info(\"=\"*50)\n    logger.info(f\"Stratégie: {report.get('strategy')}\")\n    logger.info(f\"Total trades: {report.get('total_trades')}\")\n    logger.info(f\"Win rate: {report.get('win_rate'):.2f}%\")\n    logger.info(f\"Total return: {report.get('total_return_percent'):.2f}%\")\n    logger.info(f\"Profit factor: {report.get('profit_factor'):.2f}\")\n    logger.info(f\"\\n✅ Rapport sauvegardé: {args.output}\")\n\n\nif __name__ == \"__main__\":\n    main()\n